`def_readonly` is for read-only access to member instances, e.g. when you want to provide direct access to `x` in:
```C++
class A {
public:
    int x = 5;
};
```

In your case what you want is the the `def_property_*` methods which take getter/setter member functions, i.e. in your case: `.def_property_readonly("x", &A::x)`.

In `a.cpp`:

    #include <pybind11/pybind11.h>
    
    #include "mytype.h"
    
    namespace py = pybind11;
    
    PYBIND11_DECLARE_HOLDER_TYPE(T, std::shared_ptr<T>);
        
    class A {
    };
    
    PYBIND11_PLUGIN(amod) {
        py::module m("amod", "module a");
    
        py::class_<mynamespace::MyType, std::shared_ptr<mynamespace::MyType>>(m, "MyType")
            .def(py::init<>());
    
        py::class_<A>(m, "A")
            .def(py::init<>())
            .def("test", [](A &ds, std::shared_ptr<mynamespace::MyType> &t) { return 0; });
        return m.ptr();
    }
    
and in `b.cpp`:

    #include <pybind11/pybind11.h>
    
    #include "mytype.h"
    
    namespace py = pybind11;
    
    PYBIND11_DECLARE_HOLDER_TYPE(T, std::shared_ptr<T>);
        
    class B {
    };
    
    PYBIND11_PLUGIN(bmod) {
        py::module m("bmod", "module b");
    
        py::class_<B>(m, "B")
            .def(py::init<>())
            .def("test", [](B &ds, std::shared_ptr<mynamespace::MyType> &t) { return 0; });
    
        return m.ptr();
    }

